func dockerCapAddFlags(capAdds []string) string {
	if len(capAdds) == 0 {
		return ""
	}
	var b strings.Builder
	for _, c := range capAdds {
		c = strings.TrimSpace(c)
		if c == "" {
			continue
		}
		fmt.Fprintf(&b, "--cap-add %s ", c)
	}
	return b.String()
}

