		rc.DockerCapAdd = append(rc.DockerCapAdd, "NET_ADMIN")
	}
	// Install iptables for Agent Workflow Firewall (awf) which needs it to manage DOCKER-USER chain.
	// Only add the default if the user hasn't specified a custom pre_setup script.
	// Uses /tmp for apt cache to work around read-only filesystem issues. Installation errors are non-fatal.
	if rc.DockerPreSetup == "" {
