// Docker-mode runners always report as Linux regardless of host OS.
func DefaultLabels(mode, hostOS, arch string) []string {
	labels := []string{"self-hosted"}

	osLabel := ""
	switch mode {
	case "docker":
		osLabel = "Linux"
	default:
		switch hostOS {
		case "linux":
			osLabel = "Linux"
		case "darwin":
			osLabel = "macOS"
		case "windows":
			osLabel = "Windows"
		}
	}
	if osLabel != "" {
		labels = append(labels, osLabel)
	}

	archLabel := ""
	switch arch {
	case "amd64":
		archLabel = "X64"
	case "arm64":
		archLabel = "ARM64"
	}
	if archLabel != "" {
		labels = append(labels, archLabel)
	}

	return labels
}

// EffectiveLabels returns the runner's labels, auto-generating them from host info if empty.
// Agentic-profile runners automatically get an "agentic" label appended.
func (rc *RunnerConfig) EffectiveLabels(hostOS, arch string) []string {
	var labels []string
	if len(rc.Labels) > 0 {
		labels = rc.Labels
	} else {
		mode := rc.EffectiveMode(hostOS)
		labels = DefaultLabels(mode, hostOS, arch)
	}
	if rc.IsAgentic() && !hasLabel(labels, "agentic") {
		labels = append(labels, "agentic")
	}
	return labels
}

func hasLabel(labels []string, target string) bool {
	for _, l := range labels {
		if strings.EqualFold(l, target) {
			return true
		}
	}
	return false
}

func (rc *RunnerConfig) InstanceNames() []string {
	count := rc.Count
	if count < 1 {
		count = 1
	}
	names := make([]string, count)
	for i := range count {
		names[i] = fmt.Sprintf("%s-%d", rc.Name, i+1)
	}
	return names
}

func Load(path string) (*Config, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("reading config: %w", err)
	}

	var cfg Config
	if err := yaml.Unmarshal(data, &cfg); err != nil {
		return nil, fmt.Errorf("parsing config: %w", err)
	}

	cfg.resolveEnvRefs()
	cfg.applyDefaults()

	if err := cfg.Validate(); err != nil {
		return nil, err
	}

	return &cfg, nil
}

